// Build the Resend batch: one bulletproof format-C issue per subscriber (own unsub token +
// List-Unsubscribe one-click header + plain-text part) plus one monitor copy to Manu.
const guard = $('Parse Ollama + Guard').first().json;
const featured = guard.featured || [];
const quickhits = guard.quickhits || [];
const issueNumber = guard.issue_number;
const intro = (guard.intro || '').trim();
const outro = (guard.outro || '').trim();
const dateLabel = new Date(guard.date_iso).toLocaleDateString('fr-FR', { weekday: 'long', day: 'numeric', month: 'long' });
const subs = items.map((i) => i.json).filter((s) => s && s.email && s.token);

const SITE = $env.BRIEF_SITE_URL || 'https://taiyka.com';
const FROM = $env.BRIEF_FROM_EMAIL || 'Le Brief <brief@send.taiyka.com>';
const ADDRESS = 'Taiyka · 180 Montée de Bellevue, 83210 Solliès-Pont, France';
const issueStr = String(issueNumber).padStart(3, '0');
const subject = (guard.subject && guard.subject.length) ? guard.subject : ('Le Brief #' + issueStr);
const preheader = intro ? intro.slice(0, 110) : ('Édition #' + issueStr + ' — ' + dateLabel);

const esc = (s) => String(s == null ? '' : s).replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;');
const FONT = "-apple-system,BlinkMacSystemFont,'Segoe UI',Roboto,Helvetica,Arial,sans-serif";

function render(unsubUrl) {
  const featuredHtml = featured.map((s, i) => (
    '<tr><td class="px" style="padding:18px 32px 0 32px;">' +
    '<table role="presentation" width="100%" cellpadding="0" cellspacing="0" border="0" class="bg-card" style="background-color:#0d1e33;border:1px solid #1e3a5f;border-radius:12px;">' +
    '<tr><td style="padding:20px 22px;border-left:3px solid #00A6FF;">' +
    '<table role="presentation" width="100%" cellpadding="0" cellspacing="0" border="0"><tr>' +
    '<td width="30" valign="top" style="font-family:ui-monospace,Menlo,monospace;font-size:13px;letter-spacing:0.06em;color:#00A6FF;padding-top:4px;">' + String(i + 1).padStart(2, '0') + '</td>' +
    '<td valign="top">' +
    '<a href="' + s.url + '" class="t-light" style="font-family:' + FONT + ';font-size:18px;line-height:25px;font-weight:800;letter-spacing:-0.2px;color:#E8F0FE;text-decoration:none;">' + esc(s.title) + '</a>' +
    '<div class="t-muted" style="font-family:' + FONT + ';font-size:14px;line-height:22px;color:#b8c6db;margin-top:8px;">' + esc(s.lines) + '</div>' +
    '<a href="' + s.url + '" style="font-family:' + FONT + ';font-size:13px;line-height:18px;font-weight:600;color:#00A6FF;text-decoration:none;display:inline-block;margin-top:10px;">→&nbsp;' + esc(s.source) + '</a>' +
    '</td></tr></table></td></tr></table></td></tr>'
  )).join('');

  const quickHtml = quickhits.map((s) => (
    '<tr><td class="px" style="padding:11px 32px 0 32px;">' +
    '<table role="presentation" width="100%" cellpadding="0" cellspacing="0" border="0"><tr>' +
    '<td valign="top" width="16" style="font-family:' + FONT + ';font-size:15px;line-height:22px;color:#00A6FF;">›</td>' +
    '<td valign="top" class="t-light" style="font-family:' + FONT + ';font-size:15px;line-height:22px;color:#E8F0FE;">' +
    '<a href="' + s.url + '" style="color:#E8F0FE;text-decoration:none;">' + esc(s.line) + '</a>' +
    (s.source ? ' <a href="' + s.url + '" class="t-muted" style="font-size:12px;color:#8FA3BD;text-decoration:none;white-space:nowrap;">— ' + esc(s.source) + '</a>' : '') +
    '</td></tr></table></td></tr>'
  )).join('');

  const quickBlock = quickhits.length ? (
    '<tr><td class="px" style="padding:26px 32px 0 32px;"><table role="presentation" width="100%" cellpadding="0" cellspacing="0" border="0"><tr><td style="height:1px;line-height:1px;font-size:0;background-color:#1e3a5f;">&nbsp;</td></tr></table></td></tr>' +
    '<tr><td class="px" style="padding:22px 32px 2px 32px;"><span style="font-family:' + FONT + ';font-size:12px;line-height:16px;font-weight:700;letter-spacing:2px;text-transform:uppercase;color:#00E5FF;">En bref</span></td></tr>' +
    quickHtml
  ) : '';

  const introBlock = intro ? ('<tr><td class="px t-muted" style="padding:22px 32px 0 32px;font-family:' + FONT + ';font-size:15px;line-height:24px;color:#8FA3BD;">' + esc(intro) + '</td></tr>') : '';
  const outroBlock = outro ? ('<tr><td class="px t-muted" style="padding:22px 32px 0 32px;font-family:' + FONT + ';font-size:15px;line-height:24px;color:#8FA3BD;">' + esc(outro) + '</td></tr>') : '';

  return '<!doctype html><html lang="fr" xmlns="http://www.w3.org/1999/xhtml" xmlns:v="urn:schemas-microsoft-com:vml" xmlns:o="urn:schemas-microsoft-com:office:office"><head>' +
    '<meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><meta http-equiv="X-UA-Compatible" content="IE=edge">' +
    '<meta name="x-apple-disable-message-reformatting"><meta name="color-scheme" content="dark light"><meta name="supported-color-schemes" content="dark light"><title>Le Brief</title>' +
    '<!--[if mso]><noscript><xml><o:OfficeDocumentSettings><o:PixelsPerInch>96</o:PixelsPerInch><o:AllowPNG/></o:OfficeDocumentSettings></xml></noscript><![endif]-->' +
    '<style>:root{color-scheme:dark light;supported-color-schemes:dark light;}' +
    'html,body{margin:0!important;padding:0!important;width:100%!important;}table,td{mso-table-lspace:0pt!important;mso-table-rspace:0pt!important;border-collapse:collapse!important;}' +
    'a{text-decoration:none;}a[x-apple-data-detectors]{color:inherit!important;text-decoration:none!important;}' +
    '@media only screen and (max-width:600px){.full{width:100%!important;max-width:100%!important;}.px{padding-left:20px!important;padding-right:20px!important;}}' +
    '@media (prefers-color-scheme:dark){.bg-body{background-color:#0A1628!important;}.bg-card{background-color:#0d1e33!important;}.t-light{color:#E8F0FE!important;}.t-muted{color:#8FA3BD!important;}}' +
    '[data-ogsc] .bg-body{background-color:#0A1628!important;}[data-ogsc] .bg-card{background-color:#0d1e33!important;}[data-ogsc] .t-light{color:#E8F0FE!important;}[data-ogsc] .t-muted{color:#8FA3BD!important;}' +
    '</style></head>' +
    '<body id="body" class="bg-body" style="margin:0;padding:0;width:100%;background-color:#0A1628;">' +
    '<div style="display:none;font-size:1px;line-height:1px;max-height:0;max-width:0;opacity:0;overflow:hidden;mso-hide:all;color:#0A1628;">' + esc(preheader) + '</div>' +
    '<table role="presentation" class="bg-body" width="100%" cellpadding="0" cellspacing="0" border="0" style="background-color:#0A1628;"><tr><td align="center" style="padding:0;">' +
    '<!--[if mso]><table role="presentation" align="center" width="600" cellpadding="0" cellspacing="0" border="0"><tr><td><![endif]-->' +
    '<table role="presentation" class="full" width="600" cellpadding="0" cellspacing="0" border="0" style="width:600px;max-width:600px;margin:0 auto;">' +
    '<tr><td style="height:24px;line-height:24px;font-size:0;">&nbsp;</td></tr>' +
    // header
    '<tr><td class="px" style="padding:0 32px;"><table role="presentation" width="100%" cellpadding="0" cellspacing="0" border="0"><tr>' +
    '<td align="left" style="font-family:' + FONT + ';"><span class="t-light" style="font-size:25px;line-height:30px;font-weight:800;letter-spacing:-0.5px;color:#E8F0FE;">Le&nbsp;Brief</span> <span style="font-size:25px;font-weight:800;color:#00A6FF;">/</span></td>' +
    '<td align="right" class="t-muted" style="font-family:' + FONT + ';font-size:12px;line-height:17px;color:#8FA3BD;font-weight:500;">édition #' + issueStr + '<br>' + dateLabel + '</td>' +
    '</tr></table></td></tr>' +
    // accent divider
    '<tr><td class="px" style="padding:16px 32px 0 32px;"><table role="presentation" width="100%" cellpadding="0" cellspacing="0" border="0"><tr><td style="height:2px;line-height:2px;font-size:0;background-color:#00A6FF;border-radius:2px;">&nbsp;</td></tr></table></td></tr>' +
    introBlock +
    // featured label
    '<tr><td class="px" style="padding:28px 32px 0 32px;"><span style="font-family:' + FONT + ';font-size:12px;line-height:16px;font-weight:700;letter-spacing:2px;text-transform:uppercase;color:#00E5FF;">À la une</span></td></tr>' +
    featuredHtml +
    quickBlock +
    // outro divider + outro + signoff
    '<tr><td class="px" style="padding:32px 32px 0 32px;"><table role="presentation" width="100%" cellpadding="0" cellspacing="0" border="0"><tr><td style="height:1px;line-height:1px;font-size:0;background-color:#1e3a5f;">&nbsp;</td></tr></table></td></tr>' +
    outroBlock +
    '<tr><td class="px" style="padding:16px 32px 0 32px;font-family:' + FONT + ';font-size:15px;line-height:22px;"><span class="t-light" style="color:#E8F0FE;font-weight:700;">Manu</span><span class="t-muted" style="color:#8FA3BD;">&nbsp;·&nbsp;</span><a href="https://instagram.com/manu_ai.to" style="color:#00A6FF;text-decoration:none;font-weight:600;">@manu_ai.to</a></td></tr>' +
    '<tr><td style="height:32px;line-height:32px;font-size:0;">&nbsp;</td></tr>' +
    // legal footer
    '<tr><td class="px" style="padding:0 32px;"><table role="presentation" width="100%" cellpadding="0" cellspacing="0" border="0" class="bg-card" style="background-color:#0d1e33;border:1px solid #1e3a5f;border-radius:12px;"><tr>' +
    '<td style="padding:20px 24px;font-family:' + FONT + ';font-size:12px;line-height:19px;color:#8FA3BD;text-align:center;">' +
    '<span style="color:#E8F0FE;font-weight:700;">Le Brief</span> — par Taiyka<br>' + ADDRESS + '<br><br>' +
    'Tu reçois cet email car tu t’es inscrit sur <a href="' + SITE + '" style="color:#00A6FF;text-decoration:none;">taiyka.com</a>. On ne partage jamais ton adresse.<br><br>' +
    '<a href="' + unsubUrl + '" style="color:#8FA3BD;text-decoration:underline;">Se désabonner en un clic</a>' +
    '</td></tr></table></td></tr>' +
    '<tr><td style="height:28px;line-height:28px;font-size:0;">&nbsp;</td></tr>' +
    '</table><!--[if mso]></td></tr></table><![endif]--></td></tr></table></body></html>';
}

function renderText(unsubUrl) {
  const fLines = featured.map((s, i) => String(i + 1).padStart(2, '0') + '. ' + s.title + '\n' + s.lines + '\n→ ' + s.source + ': ' + s.url).join('\n\n');
  const qLines = quickhits.map((s) => '› ' + s.line + (s.source ? ' (' + s.source + ')' : '') + '\n  ' + s.url).join('\n');
  return 'LE BRIEF #' + issueStr + ' — ' + dateLabel + '\n\n' +
    (intro ? intro + '\n\n' : '') +
    'A LA UNE\n\n' + fLines + '\n\n' +
    (quickhits.length ? 'EN BREF\n\n' + qLines + '\n\n' : '') +
    (outro ? outro + '\n\n' : '') +
    'Manu · @manu_ai.to\n\n' +
    ADDRESS + '\nTu reçois cet email car tu t’es inscrit sur taiyka.com.\nSe désabonner: ' + unsubUrl;
}

const unsubHeaders = (unsubUrl) => ({
  'List-Unsubscribe': '<' + unsubUrl + '>, <mailto:unsubscribe@taiyka.com?subject=unsubscribe>',
  'List-Unsubscribe-Post': 'List-Unsubscribe=One-Click',
});

const batch = [];
// Monitor copy to Manu (visibility for the first ~2 weeks).
const monUnsub = SITE + '/brief';
batch.push({ from: FROM, to: 'manu.uhila@taiyka.com', subject: '[COPIE] ' + subject, html: render(monUnsub), text: renderText(monUnsub) });
for (const s of subs) {
  const unsub = SITE + '/api/brief/unsubscribe?token=' + s.token;
  batch.push({ from: FROM, to: s.email, subject, html: render(unsub), text: renderText(unsub), headers: unsubHeaders(unsub) });
}

return [{ json: { batch, sent_count: subs.length, story_count: (featured.length + quickhits.length) } }];
